import React from 'react';
import { Dialog, DialogTitle, DialogContent, TextField, Button, DialogActions, FormControlLabel, Radio, RadioGroup } from '@mui/material';
import { Formik, Form, Field, FieldArray } from 'formik';
import * as Yup from 'yup';

// Validation schema using Yup
const customerSchema = Yup.object().shape({
  companyName: Yup.string().required('Company name is required'),
  legalBusinessName: Yup.string().required('Legal business name is required'),
  email: Yup.string().email('Invalid email').required('Email is required'),
  phone: Yup.string().required('Phone number is required'),
  address: Yup.string().required('Address is required'),
  city: Yup.string().required('City is required'),
  state: Yup.string().required('State is required'),
  zip: Yup.string().required('Zip code is required'),
  country: Yup.string().required('Country is required'),
  accountsPayable: Yup.array().of(
    Yup.object().shape({
      name: Yup.string().required('Name is required'),
      email: Yup.string().email('Invalid email').required('Email is required'),
      phone: Yup.string().required('Phone number is required'),
    })
  ),
  businessType: Yup.string().required('Business type is required')
});

const CustomerModal = ({ open, handleClose }) => {
  return (
    <Dialog open={open} onClose={handleClose}>
      <DialogTitle>Create Customer</DialogTitle>
      <Formik
        initialValues={{
          companyName: '',
          legalBusinessName: '',
          email: '',
          phone: '',
          address: '',
          city: '',
          state: '',
          zip: '',
          country: '',
          accountsPayable: [{ name: '', email: '', phone: '' }],
          businessType: ''
        }}
        validationSchema={customerSchema}
        onSubmit={(values, { setSubmitting }) => {
          console.log(values);
          setSubmitting(false);
          handleClose();
        }}
      >
        {({ values, errors, touched }) => (
          <Form>
            <DialogContent>
              {/* Existing fields */}
              {/* Dynamic Account Payable Fields */}
              <FieldArray name="accountsPayable">
                {({ insert, remove, push }) => (  // Ensure helpers are correctly destructured here
                  values.accountsPayable.map((account, index) => (
                    <div key={index}>
                      <Field name={`accountsPayable.${index}.name`} placeholder="Name" type="text" as={TextField} fullWidth />
                      <Field name={`accountsPayable.${index}.email`} placeholder="Email" type="email" as={TextField} fullWidth />
                      <Field name={`accountsPayable.${index}.phone`} placeholder="Phone" type="text" as={TextField} fullWidth />
                      <Button
                        type="button"
                        onClick={() => remove(index)} // Use remove function here
                      >Remove</Button>
                    </div>
                  ))
                )}
                <Button
                  type="button"
                  onClick={() => push({ name: '', email: '', phone: '' })} // Use push function here
                >Add More</Button>
              </FieldArray>
              {/* Business Type Radio Buttons */}
              <RadioGroup name="businessType">
                {/* Radio buttons */}
              </RadioGroup>
            </DialogContent>
            <DialogActions>
              <Button onClick={handleClose}>Cancel</Button>
              <Button type="submit" color="primary">Save and Close</Button>
            </DialogActions>
          </Form>
        )}
      </Formik>
    </Dialog>
  );
};

export default CustomerModal;
